const req = $json;
const body = req.body || req || {};
const errors = [];
const required = ['campaign_id', 'workspace_id', 'solutions'];
for (const key of required) {
  if (body[key] === undefined || body[key] === null || body[key] === '') {
    errors.push('Missing required field: ' + key);
  }
}
if (body.solutions !== undefined && !Array.isArray(body.solutions)) {
  errors.push('Field solutions must be an array');
}
return [{
  json: {
    campaign_id: body.campaign_id || null,
    workspace_id: body.workspace_id || null,
    solutions: Array.isArray(body.solutions) ? body.solutions : [],
    strategy: body.strategy || {},
    valid_request: errors.length === 0,
    validation_errors: errors,
    received_at: new Date().toISOString()
  }
}];

const payload = $node['W2 Validate Payload'].json;
const memoryRow = $json || {};
const parseJsonLike = (v, fallback) => {
  if (v === null || v === undefined) return fallback;
  if (typeof v === 'string') {
    try { return JSON.parse(v); } catch (e) { return fallback; }
  }
  return v;
};
const banned = parseJsonLike(memoryRow.banned_phrases, []);
const bannedPhrases = Array.isArray(banned) ? banned.map(x => String(x).trim().toLowerCase()).filter(Boolean) : [];
const flagged = [];
for (const sol of payload.solutions || []) {
  const hay = [sol.reasoning, sol.copy, sol.caption, sol.text].filter(Boolean).join('\n').toLowerCase();
  for (const term of bannedPhrases) {
    if (term && hay.includes(term)) {
      flagged.push({
        solution_id: sol.id || null,
        issue: 'Contains banned phrase: "' + term + '"',
        severity: 'high'
      });
    }
  }
}
return [{
  json: {
    ...payload,
    all_pass: flagged.length === 0,
    flagged_issues: flagged,
    max_budget: memoryRow.max_budget === null || memoryRow.max_budget === undefined ? null : Number(memoryRow.max_budget)
  }
}];

const input = $json;
const issues = [];
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
};
let total = 0;
for (const sol of input.solutions || []) {
  const amount = toNum(sol.budget_estimate ?? sol.budget ?? sol.estimated_cost ?? 0);
  total += amount;
  if (input.max_budget !== null && input.max_budget !== undefined && amount > Number(input.max_budget)) {
    issues.push({
      solution_id: sol.id || null,
      issue: 'Solution budget exceeds max_budget',
      amount,
      max_budget: Number(input.max_budget),
      severity: 'high'
    });
  }
}
if (input.max_budget !== null && input.max_budget !== undefined && total > Number(input.max_budget)) {
  issues.push({
    solution_id: null,
    issue: 'Total budget exceeds max_budget',
    amount: total,
    max_budget: Number(input.max_budget),
    severity: 'high'
  });
}
const rejection_issues = [...(input.flagged_issues || []), ...issues];
return [{ json: { ...input, budget_ok: issues.length === 0, total_budget: total, rejection_issues } }];
